const crypto = require('crypto');
const fs = require('fs');
const path = require('path');
const p = path.join(process.cwd(), 'tmp.txt');
fs.writeFileSync(p, 'abc', 'utf8');
const s = fs.readFileSync(p, 'utf8');
const h = crypto.createHash('sha256').update(s).digest('hex');
console.log(h);
